head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"chartIntervalCount" : 5,
		"acmtrtChartUnit" : 10,
		"acmtrtChartIntervalCount" : 3
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSPN4000000", {"initScreenCallback" : scwin.searchDatas});
	// ecsLib.setChartResizeObserver(this);
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	var strtDt = String(Number(utilLib.getCurrentDate("yyyy")) - 4);
	var endDt = utilLib.getCurrentDate("yyyy");
	var basinCd = "ALL";

	var params = $p.getParameter("param");
	if (params) {
		if (params.year) {
			strtDt = String(params.year);
			endDt = String(params.year);
			//today = String(params.year) + "1231";
		}
		if (params.basinCd) {
			basinCd = params.basinCd;
			acbBasin.setValue(basinCd);
		}
	}

	dmaSearchParam.set("strtDt", strtDt);
	dmaSearchParam.set("endDt", endDt);
	dmaSearchParam.set("basinCd", basinCd);
	dmaSearchParam.set("deptCd", "ALL");
	dmaSearchParam.set("setcscCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var endDate = dmaSearchParam.get("endDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");

	if (String(strtDate).length != 4 || String(endDate).length != 4) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	} else if (utilLib.minusYears(strtDate, endDate) > 15 ? true : false) {
		// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
		alert(utilLib.getMessage("ECS.INFO.00012", "15년")[0]);
		return;
	} else if (parseInt(strtDate) > parseInt(endDate)) {
		// 시작년이 종료년보다 클수 없습니다.
		alert(utilLib.getMessage("ECS.INFO.00015")[0]);
		return;
	}
	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;

	var option = {
		action : "pn/elyrsernsttus/retrieve-elyrs-ern-sttus.do"
			+ queryString,
		method : "get",
		resData : dltElyrsErnSttusList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	// 전력 거래량 차트 생성
	scwin.setChartEpwrDelngQy();
	// 발전수익 차트 생성
	scwin.setChartElyrsErn();
	// 판매단가 차트 생성
	scwin.searchChartSleUpc();
};

scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=dept"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbSetcsc_onviewchange = function(info) {
	var ecsSetcscDivCd = info.newValue;
	dmaSearchParam.set("setcscCd", ecsSetcscDivCd);
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=dept"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbDept_onviewchange = function(info) {
	dmaSearchParam.set("deptCd", info.newValue);
};

/**
 * 그리드 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplZeroFrmt = function(value) {
	return ecsLib.dsplZeroFrmt(value, 1);
};

/**
 * 그리드 합계 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplFrmt = function(value) {
	return ecsLib.dsplFrmt(value, 1);
};

//============================================================================================
// 차트
//============================================================================================
/**
 * 전력 거래량 차트를 생성
 */
scwin.setChartEpwrDelngQy = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerEpwrDelngQy";
	rMateChartH5.create($p.id + "chartEpwrDelngQy", grpChartEpwrDelngQy.getID(), chartVars, "100%", "100%");
};

/**
* 전력 거래량 차트 설정
*/
scwin.chartReadyHandlerEpwrDelngQy = function(id) {
	var epwrDelngQyData = dltElyrsErnSttusList.getAllJSON();
	var chartData = [];

	for (var idx = 0; idx < epwrDelngQyData.length; idx++) {
		var obj = {
			"Year" : epwrDelngQyData[idx].year,
			"Plan" : epwrDelngQyData[idx].epwrDelngQyPlan,
			"Acmslt" : epwrDelngQyData[idx].epwrDelngQyAcmslt,
			"Acmtrt" : epwrDelngQyData[idx].epwrDelngQyAcmtrt
		}
		chartData.push(obj);
	}

	var maxData = chartData.reduce((max, obj) => Math.max(max, obj.Plan, obj.Acmslt), 0);
	var acmtrtMaxData = chartData.reduce((max, obj) => Math.max(max, obj.Acmtrt), 0);

	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;
	var acmtrtChartUnit = Math.max(scwin.initData.chart.acmtrtChartUnit, Math.pow(10, String(acmtrtMaxData.toFixed(0)).length - 2));
	var acmtrtInterval = Math.ceil((acmtrtMaxData / scwin.initData.chart.acmtrtChartIntervalCount) / acmtrtChartUnit) * acmtrtChartUnit;

	var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" borderStyle="none">'
		+ '	<Options>'
		+ '		<Caption text="전력거래량(GWh)" />'
		+ '		<Legend defaultMouseOverAction="true" />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis categoryField="Year" padding="0.7" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="GWh"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '				<series>'
		+ '					<Column2DSeries yField="Plan" displayName="계획(GWh)">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor1 + '" />'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '					<Column2DSeries yField="Acmslt" displayName="실적(GWh)">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor2 + '" />'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '				</series>'
		+ '			</Column2DSet>'
		+ '			<Line2DSeries yField="Acmtrt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="달성률(%)" labelPosition="up">'
		+ '				<stroke>'
		+ '					<Stroke color="#F9BD03" weight="3" />'
		+ '				</stroke>'
		+ '				<lineStroke>'
		+ '					<Stroke color="#F9BD03" weight="3" />'
		+ '				</lineStroke>'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxis2" interval="' + acmtrtInterval + '" formatter="{numFmt}" title="%"/>'
		+ '				</verticalAxis>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Line2DSeries>'
		+ '		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '			<Axis2DRenderer axis="{vAxis2}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '	</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 발전수익 차트를 생성
 */
scwin.setChartElyrsErn = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerElyrsErn";
