/**
 * 판매단가 차트를 생성
 */
scwin.searchChartSleUpc = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerSleUpc";
	rMateChartH5.create($p.id + "chartSleUpc", grpChartSleUpc.getID(), chartVars, "100%", "100%");
};

/**
* 판매단가 차트 설정
*/
scwin.chartReadyHandlerSleUpc = function(id) {
	var sleUpcData = dltElyrsErnSttusList.getAllJSON();
	var chartData = [];

	for (var idx = 0; idx < sleUpcData.length; idx++) {
		var obj = {
			"Year" : sleUpcData[idx].year,
			"Plan" : sleUpcData[idx].sleUpcPlan,
			"Acmslt" : sleUpcData[idx].sleUpcAcmslt,
			"Acmtrt" : sleUpcData[idx].sleUpcAcmtrt
		}
		chartData.push(obj);
	}

	var maxData = chartData.reduce((max, obj) => Math.max(max, obj.Plan, obj.Acmslt), 0);
	var acmtrtMaxData = chartData.reduce((max, obj) => Math.max(max, obj.Acmtrt), 0);

	var chartUnit = Math.max(20, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / 20) * 20;
	var acmtrtChartUnit = Math.max(scwin.initData.chart.acmtrtChartUnit, Math.pow(10, String(acmtrtMaxData.toFixed(0)).length - 2));
	var acmtrtInterval = Math.ceil((acmtrtMaxData / scwin.initData.chart.acmtrtChartIntervalCount) / acmtrtChartUnit) * acmtrtChartUnit;

	var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" borderStyle="none">'
		+ '	<Options>'
		+ '		<Caption text="판매단가(원/kWh)" />'
		+ '		<Legend defaultMouseOverAction="true" />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis categoryField="Year" padding="0.7" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="원/kWh"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '				<series>'
		+ '					<Column2DSeries yField="Plan" displayName="계획(원/kWh)">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor1 + '" />'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '					<Column2DSeries yField="Acmslt" displayName="실적(원/kWh)">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor2 + '" />'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '				</series>'
		+ '			</Column2DSet>'
		+ '			<Line2DSeries yField="Acmtrt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="달성률(%)" labelPosition="up">'
		+ '				<stroke>'
		+ '					<Stroke color="#F9BD03" weight="3" />'
		+ '				</stroke>'
		+ '				<lineStroke>'
		+ '					<Stroke color="#F9BD03" weight="3" />'
		+ '				</lineStroke>'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxis2" interval="' + acmtrtInterval + '" formatter="{numFmt}" title="%"/>'
		+ '				</verticalAxis>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Line2DSeries>'
		+ '		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '			<Axis2DRenderer axis="{vAxis2}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '	</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

// 전력거래량 달성률 계산_240122
scwin.fEpwrDelngQyAcmtrtCalc = function() {
	var fEpwrDelngQyPlanData = grdElyrsErnSttusList.getFooterData("fEpwrDelngQyPlan");
	var fEpwrDelngQyAcmsltData = grdElyrsErnSttusList.getFooterData("fEpwrDelngQyAcmslt");
	return fEpwrDelngQyAcmsltData / fEpwrDelngQyPlanData * 100;
};

// 발전수익 달성률 계산_240122
scwin.fElyrsErnAcmtrtCalc = function() {
	var fElyrsErnPlanData = grdElyrsErnSttusList.getFooterData("fElyrsErnPlan");
	var fElyrsErnAcmsltData = grdElyrsErnSttusList.getFooterData("fElyrsErnAcmslt");
	return fElyrsErnAcmsltData / fElyrsErnPlanData * 100;
};

// 판매단가 달성률 계산_240122
scwin.fSleUpcAcmtrtCalc = function() {
	var fSleUpcPlanData = grdElyrsErnSttusList.getFooterData("fSleUpcPlan");
	var fSleUpcAcmsltData = grdElyrsErnSttusList.getFooterData("fSleUpcAcmslt");
	return fSleUpcAcmsltData / fSleUpcPlanData * 100;
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 10,
		text 		: `${menuNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdElyrsErnSttusList, {
		fileName : `${menuNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		useDataFormat: true,
		applyDataFormat : true,
		decimal : "auto"
	}, infoArr);
};
